Representing position and velocity components and updating them in flat system loops:

```cpp
#include <vector>

struct FPositionComponent {
    float X, Y;
};

struct FVelocityComponent {
    float VX, VY;
};

// Flat contiguous arrays are extremely cache friendly
std::vector<FPositionComponent> Positions;
std::vector<FVelocityComponent> Velocities;

void MovementSystem(float dt) {
    const size_t Count = Positions.size();
    for (size_t i = 0; i < Count; ++i) {
        // Sequential memory accesses trigger hardware pre-fetching
        Positions[i].X += Velocities[i].VX * dt;
        Positions[i].Y += Velocities[i].VY * dt;
    }
}
```
